const body = $input.first().json.body;
const command = body.command || '/ai';
const rawText = (body.text || '').trim();
const userId = body.user_id || '';
const userName = body.user_name || 'unknown';
const channelId = body.channel_id || '';
const channelName = body.channel_name || '';
const responseUrl = body.response_url || '';

// Personality routing: text prefix takes priority, then channel name
const AGENTS = ['kevin','jason','scaachi','christian','chidi'];
let agent = 'kevin'; // default
let userText = rawText;

// Check text prefix: "kevin: question" or "kevin question"
for (const a of AGENTS) {
  const prefixColon = a + ':';
  const prefixSpace = a + ' ';
  if (rawText.toLowerCase().startsWith(prefixColon)) {
    agent = a;
    userText = rawText.slice(prefixColon.length).trim();
    break;
  } else if (rawText.toLowerCase().startsWith(prefixSpace)) {
    agent = a;
    userText = rawText.slice(prefixSpace.length).trim();
    break;
  }
}

// Fall back to channel name routing (counsel-kevin -> kevin)
if (agent === 'kevin' && userText === rawText) {
  for (const a of AGENTS) {
    if (channelName.includes(a)) {
      agent = a;
      break;
    }
  }
}

// Special commands
if (command === '/ai-status') agent = '__status';
if (command === '/ai-diagnose') agent = '__diagnose';
if (command === '/ai-draw') agent = '__draw';

const MODEL_MAP = {
  kevin: 'kevin:latest',
  jason: 'jason:latest',
  scaachi: 'scaachi:latest',
  christian: 'christian:latest',
  chidi: 'chidi:latest'
};

return [{
  json: {
    command, rawText, userText, userId, userName,
    channelId, channelName, responseUrl,
    agent,
    model: MODEL_MAP[agent] || 'kevin:latest',
    isSpecialCommand: agent.startsWith('__')
  }
}];

const ollamaResp = $input.first().json;
const prevData = $('Parse Command').first().json;

const content = ollamaResp.message?.content || 'No response from model.';
const agent = prevData.agent || 'ai-worker';
const userName = prevData.userName || 'you';

// Slack has a 3000 char limit per block text; truncate if needed
const MAX = 2800;
const truncated = content.length > MAX
  ? content.slice(0, MAX) + '\n_[response truncated]_'
  : content;

return [{
  json: {
    responseUrl: prevData.responseUrl,
    agent,
    slackPayload: {
      response_type: 'in_channel',
      blocks: [
        {
          type: 'context',
          elements: [{ type: 'mrkdwn', text: `:robot_face: *${agent}* responding to <@${prevData.userId}>` }]
        },
        {
          type: 'section',
          text: { type: 'mrkdwn', text: truncated }
        }
      ]
    }
  }
}];

const data = $('Parse Command').first().json;
return [{ json: {
  responseUrl: data.responseUrl,
  slackPayload: {
    response_type: 'ephemeral',
    text: ':construction: Special commands (/ai-status, /ai-diagnose, /ai-draw) are coming soon.'
  }
}}];
